49: /**
50:  * A single-name credit default swap (CDS).
51:  * <p>
52:  * A CDS is a financial instrument where the protection seller agrees to compensate
53:  * the protection buyer when the reference entity suffers a default.
54:  * The protection seller is paid premium regularly from the protection buyer until
55:  * the expiry of the CDS contract or the reference entity defaults before the expiry.
56:  */
57: @BeanDefinition
58: public final class Cds
59:     implements Product, Resolvable<ResolvedCds>, ImmutableBean, Serializable {
60: 
61:   /**
62:    * Whether the CDS is buy or sell.
63:    * <p>
64:    * A value of 'Buy' implies buying protection, where the fixed coupon is paid
65:    * and the protection is received  in the event of default.
66:    * A value of 'Sell' implies selling protection, where the fixed coupon is received
67:    * and the protection is paid in the event of default.
68:    */
69:   @PropertyDefinition(validate = "notNull")
70:   private final BuySell buySell;
71:   /**
72:    * The legal entity identifier.
73:    * <p>
74:    * This identifier is used for the reference legal entity of the CDS.
75:    */
76:   @PropertyDefinition(validate = "notNull")
77:   private final StandardId legalEntityId;
78:   /**
79:    * The currency of the CDS.
80:    * <p>
81:    * The amounts of the notional are expressed in terms of this currency.
82:    */
83:   @PropertyDefinition(validate = "notNull")
84:   private final Currency currency;
85:   /**
86:    * The notional amount, must be non-negative.
87:    * <p>
88:    * The fixed notional amount applicable during the lifetime of the CDS.
89:    * The currency of the notional is specified by {@code currency}.
90:    */
91:   @PropertyDefinition(validate = "ArgChecker.notNegativeOrZero")
92:   private final double notional;
93:   /**
94:    * The payment schedule.
95:    * <p>
96:    * This is used to define the payment periods.
97:    */
98:   @PropertyDefinition(validate = "notNull")
99:   private final PeriodicSchedule paymentSchedule;
100:   /**
101:    * The fixed coupon rate.
102:    * <p>
103:    * This must be represented in decimal form.
104:    */
105:   @PropertyDefinition(validate = "ArgChecker.notNegative")
106:   private final double fixedRate;
107:   /**
108:    * The day count convention.
109:    * <p>
110:    * This is used to convert dates to a numerical value.
111:    * <p>
112:    * When building, this will default to 'Act/360'.
113:    */
114:   @PropertyDefinition(validate = "notNull")
115:   private final DayCount dayCount;
116:   /**
117:    * The payment on default.
118:    * <p>
119:    * Whether the accrued premium is paid in the event of a default.
120:    * <p>
121:    * When building, this will default to 'AccruedPremium'.
122:    */
123:   @PropertyDefinition(validate = "notNull")
124:   private final PaymentOnDefault paymentOnDefault;
125:   /**
126:    * The protection start of the day.
127:    * <p>
128:    * When the protection starts on the start date.
129:    * <p>
130:    * When building, this will default to 'Beginning'.
131:    */
132:   @PropertyDefinition(validate = "notNull")
133:   private final ProtectionStartOfDay protectionStart;
134:   /**
135:    * The number of days between valuation date and step-in date.
136:    * <p>
137:    * The step-in date is also called protection effective date.
138:    * It is usually 1 calendar day for standardized CDS contracts.
139:    * <p>
140:    * When building, this will default to 1 calendar day.
141:    */
142:   @PropertyDefinition(validate = "notNull")
143:   private final DaysAdjustment stepinDateOffset;
144:   /**
145:    * The number of days between valuation date and settlement date.
146:    * <p>
147:    * It is usually 3 business days for standardized CDS contracts.
148:    * <p>
149:    * When building, this will default to 3 business days in the calendar of the payment schedule.
150:    */
151:   @PropertyDefinition(validate = "notNull")
152:   private final DaysAdjustment settlementDateOffset;
153: 
154:   //-------------------------------------------------------------------------
155:   /**
156:    * Creates an instance of a standardized CDS.
157:    * 
158:    * @param buySell  buy or sell
159:    * @param legalEntityId  the legal entity ID
160:    * @param currency  the currency
161:    * @param notional  the notional
162:    * @param startDate  the start date
163:    * @param endDate  the end date
164:    * @param calendar  the calendar
165:    * @param fixedRate  the fixed coupon rate
166:    * @param paymentFrequency  the payment frequency
