28: /**
29:  * Pricer for single-name credit default swaps (CDS) based on ISDA standard model. 
30:  * <p>
31:  * The implementation is based on the ISDA model versions 1.8.2.
32:  * <p>
33:  * A CDS product is priced based on {@code referenceDate}.
34:  * This is typically valuation date, or settlement date if the product is associated with a {@code Trade}. 
35:  */
36: public class IsdaCdsProductPricer {
37: 
38:   /**
39:    * Default implementation.
40:    */
41:   public static final IsdaCdsProductPricer DEFAULT = new IsdaCdsProductPricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);
42:   /**
43:    * The small parameter.
44:    * <p>
45:    * An approximation formula is used if a certain variable is smaller than this parameter.
46:    */
47:   private static final double SMALL = 1.0e-5;
48: 
49:   /**
50:    * The formula
51:    */
52:   private final AccrualOnDefaultFormula formula;
53:   /**
54:    * The omega parameter.
55:    */
56:   private final double omega;
57: 
58:   /**
59:    * Constructor specifying the formula to use for the accrued on default calculation.  
60:    * <p>
61:    * Options are the formula given in the ISDA model (version 1.8.2 and lower); 
62:    * the proposed fix by Markit (given as a comment in version 1.8.2), or the mathematically correct formula. 
63:    *
64:    * @param formula  the formula
65:    */
66:   public IsdaCdsProductPricer(AccrualOnDefaultFormula formula) {
67:     this.formula = ArgChecker.notNull(formula, "formula");
68:     this.omega = formula.getOmega();
69:   }
70: 
71:   //-------------------------------------------------------------------------
72:   /**
73:    * Gets the accrual-on-default formula used in this pricer. 
74:    * 
75:    * @return the formula
76:    */
77:   public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
78:     return formula;
79:   }
80: 
81:   //-------------------------------------------------------------------------
82:   /**
83:    * Calculates the price of the CDS product, which is the present value per unit notional. 
84:    * <p>
85:    * This method can calculate the clean or dirty price, see {@link PriceType}. 
86:    * If calculating the clean price, the accrued interest is calculated based on the step-in date.
87:    * <p>
88:    * This is coherent with {@link #presentValue(ResolvedCds, CreditRatesProvider, LocalDate, PriceType, ReferenceData)}.
89:    * 
90:    * @param cds  the product
91:    * @param ratesProvider  the rates provider
92:    * @param referenceDate  the reference date
93:    * @param priceType  the price type
94:    * @param refData  the reference data
95:    * @return the price
96:    */
97:   public double price(
98:       ResolvedCds cds,
99:       CreditRatesProvider ratesProvider,
100:       LocalDate referenceDate,
101:       PriceType priceType,
102:       ReferenceData refData) {
103: 
104:     return price(cds, ratesProvider, cds.getFixedRate(), referenceDate, priceType, refData);
105:   }
106: 
107:   // internal price computation with specified coupon rate
108:   double price(
109:       ResolvedCds cds,
110:       CreditRatesProvider ratesProvider,
111:       double fractionalSpread,
112:       LocalDate referenceDate,
113:       PriceType priceType,
114:       ReferenceData refData) {
115: 
116:     if (!cds.getProtectionEndDate().isAfter(ratesProvider.getValuationDate())) { //short cut already expired CDSs
117:       return 0d;
118:     }
119:     LocalDate stepinDate = cds.getStepinDateOffset().adjust(ratesProvider.getValuationDate(), refData);
120:     LocalDate effectiveStartDate = cds.calculateEffectiveStartDate(stepinDate);
121:     double recoveryRate = recoveryRate(cds, ratesProvider);
122:     Pair<CreditDiscountFactors, LegalEntitySurvivalProbabilities> rates = reduceDiscountFactors(cds, ratesProvider);
123:     double protectionLeg =
124:         protectionLeg(cds, rates.getFirst(), rates.getSecond(), referenceDate, effectiveStartDate, recoveryRate);
125:     double rpv01 = riskyAnnuity(
126:         cds, rates.getFirst(), rates.getSecond(), referenceDate, stepinDate, effectiveStartDate, priceType);
127:     return protectionLeg - rpv01 * fractionalSpread;
128:   }
129: 
130:   /**
131:    * Calculates the price sensitivity of the product. 
132:    * <p>
133:    * The price sensitivity of the product is the sensitivity of price to the underlying curves.
134:    * 
135:    * @param cds  the product 
136:    * @param ratesProvider  the rates provider
137:    * @param referenceDate  the reference date
138:    * @param refData  the reference data
139:    * @return the present value sensitivity
140:    */
141:   public PointSensitivityBuilder priceSensitivity(
142:       ResolvedCds cds,
143:       CreditRatesProvider ratesProvider,
144:       LocalDate referenceDate,
145:       ReferenceData refData) {
146: 
147:     if (isExpired(cds, ratesProvider)) {
148:       return PointSensitivityBuilder.none();
149:     }
150:     LocalDate stepinDate = cds.getStepinDateOffset().adjust(ratesProvider.getValuationDate(), refData);
