30: /**
31:  * Multi-scenario measure calculations for CDS trades.
32:  * <p>
33:  * Each method corresponds to a measure, typically calculated by one or more calls to the pricer.
34:  */
35: final class CdsMeasureCalculations {
36: 
37:   /**
38:    * Default implementation.
39:    */
40:   static final CdsMeasureCalculations DEFAULT =
41:       new CdsMeasureCalculations(new IsdaCdsTradePricer(AccrualOnDefaultFormula.CORRECT));
42: 
43:   /**
44:    * The market quote sensitivity calculator.
45:    */
46:   private static final MarketQuoteSensitivityCalculator MARKET_QUOTE_SENS = MarketQuoteSensitivityCalculator.DEFAULT;
47:   /**
48:    * One basis point, expressed as a {@code double}.
49:    */
50:   private static final double ONE_BASIS_POINT = 1e-4;
51: 
52:   /**
53:    * Pricer for {@link ResolvedCdsTrade}.
54:    */
55:   private final IsdaCdsTradePricer tradePricer;
56:   /**
57:    * Spread sensitivity calculator.
58:    */
59:   private final SpreadSensitivityCalculator cs01Calculator;
60:   /**
61:    * Market quote converter.
62:    */
63:   private final CdsMarketQuoteConverter converter;
64: 
65:   /**
66:    * Creates an instance. 
67:    * 
68:    * @param tradePricer  the pricer for {@link ResolvedCdsTrade}
69:    */
70:   CdsMeasureCalculations(IsdaCdsTradePricer tradePricer) {
71:     this.tradePricer = ArgChecker.notNull(tradePricer, "tradePricer");
72:     this.cs01Calculator = new AnalyticSpreadSensitivityCalculator(tradePricer.getAccrualOnDefaultFormula());
73:     this.converter = new CdsMarketQuoteConverter(tradePricer.getAccrualOnDefaultFormula());
74:   }
75: 
76:   //-------------------------------------------------------------------------
77:   // calculates present value for all scenarios
78:   CurrencyScenarioArray presentValue(
79:       ResolvedCdsTrade trade,
80:       CreditRatesScenarioMarketData marketData,
81:       ReferenceData refData) {
82: 
83:     return CurrencyScenarioArray.of(
84:         marketData.getScenarioCount(),
85:         i -> presentValue(trade, marketData.scenario(i).creditRatesProvider(), PriceType.DIRTY, refData));
86:   }
87: 
88:   // calculates present value for one scenario
89:   CurrencyAmount presentValue(
90:       ResolvedCdsTrade trade,
91:       CreditRatesProvider ratesProvider,
92:       PriceType priceType,
93:       ReferenceData refData) {
94: 
95:     return tradePricer.presentValue(trade, ratesProvider, priceType, refData);
96:   }
97: 
98:   //-------------------------------------------------------------------------
