import com.opengamma.strata.product.ResolvableTrade;
import com.opengamma.strata.product.TradeInfo;
import com.opengamma.strata.product.common.SummarizerUtils;

/**
 * A trade in a CDS tranche.
 * <p>
 * An Over-The-Counter (OTC) trade in a {@link CdsTranche}.
 * <p>
 * A CDS tranche is a slice of credit risk from a CDS index portfolio,
 * defined by attachment and detachment points.
 */
@BeanDefinition
public final class CdsTrancheTrade
    implements ProductTrade, ResolvableTrade<ResolvedCdsTrancheTrade>, ImmutableBean, Serializable {

  /**
   * The additional trade information, defaulted to an empty instance.
   * <p>
   * This allows additional information to be attached to the trade.
   */
  @PropertyDefinition(validate = "notNull", overrideGet = true)
  private final TradeInfo info;
  /**
   * The CDS tranche product that was agreed when the trade occurred.
   * <p>
   * The product captures the contracted financial details of the trade.
   */
  @PropertyDefinition(validate = "notNull", overrideGet = true)
  private final CdsTranche product;
  /**
   * The upfront fee of the product.
   * <p>
   * This specifies a single amount payable by the buyer to the seller.
   * Thus the sign must be compatible with the product Pay/Receive flag.
   */
  @PropertyDefinition(get = "optional")
  private final AdjustablePayment upfrontFee;

  //-------------------------------------------------------------------------
  @Override
  public CdsTrancheTrade withInfo(PortfolioItemInfo info) {
    return new CdsTrancheTrade(TradeInfo.from(info), product, upfrontFee);
  }

  //-------------------------------------------------------------------------
  @Override
  public PortfolioItemSummary summarize() {
    CdsTranche tranche = product;
    CdsIndex underlyingIndex = tranche.getUnderlyingIndex();
    StringBuilder buf = new StringBuilder(128);
    buf.append(SummarizerUtils.datePeriod(
        underlyingIndex.getPaymentSchedule().getStartDate(),
        underlyingIndex.getPaymentSchedule().getEndDate()));
    buf.append(' ');
    buf.append(underlyingIndex.getBuySell());
    buf.append(' ');
    buf.append(SummarizerUtils.amount(underlyingIndex.getCurrency(), underlyingIndex.getNotional()));
    buf.append(' ');
    buf.append(underlyingIndex.getCdsIndexId().getValue());
    buf.append(" [").append(SummarizerUtils.percent(tranche.getAttachmentPoint()));
    buf.append("-").append(SummarizerUtils.percent(tranche.getDetachmentPoint()));
    buf.append("] / ");
    buf.append(SummarizerUtils.percent(underlyingIndex.getFixedRate()));
    return SummarizerUtils.summary(this, ProductType.CDS_INDEX, buf.toString(), underlyingIndex.getCurrency());
  }

  @Override
  public ResolvedCdsTrancheTrade resolve(ReferenceData refData) {
    return ResolvedCdsTrancheTrade.builder()
        .info(info)
        .product(product.resolve(refData))
        .upfrontFee(upfrontFee != null ? upfrontFee.resolve(refData) : null)
        .build();
  }

