/**
 * A CDS tranche product.
 * <p>
 * A CDS tranche represents a slice of credit risk from a CDS index portfolio, defined by
 * attachment and detachment points that determine the subordination level.
 * The tranche buyer receives protection against losses in the underlying index between
 * the attachment and detachment points.
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * The underlying CDS index.
   * <p>
   * The tranche is defined on this index portfolio.
   */
  @PropertyDefinition(validate = "notNull")
  private final CdsIndex underlyingIndex;
  /**
   * The attachment point (lower tranche boundary) as a fraction of the index notional.
   * <p>
   * This must be between 0.0 and 1.0, and must be less than the detachment point.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double attachmentPoint;
  /**
   * The detachment point (upper tranche boundary) as a fraction of the index notional.
   * <p>
   * This must be between 0.0 and 1.0, and must be greater than the attachment point.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double detachmentPoint;

  //-------------------------------------------------------------------------
  @ImmutableDefaults
  private static void applyDefaults(Builder builder) {
  }

  @ImmutablePreBuild
  private static void preBuild(Builder builder) {
    ArgChecker.isFalse(
        builder.attachmentPoint >= builder.detachmentPoint,
        "Attachment point must be less than detachment point");
    ArgChecker.isFalse(
        builder.detachmentPoint > 1.0,
        "Detachment point must be at most 1.0");
  }

  //-------------------------------------------------------------------------
  @Override
  public ImmutableSet<Currency> allCurrencies() {
    return underlyingIndex.allCurrencies();
  }

  //-------------------------------------------------------------------------
  @Override
  public ResolvedCdsTranche resolve(ReferenceData refData) {

